module carry_lookahead_adder(input [3:0] A, input [3:0] B, input Cin, output [3:0] Sum, output Cout);  
    wire [3:0] P, G;  
    wire [4:0] obf_C;  

    assign P = A ^ B;  
    assign G = A & B;  
    assign obf_C[0] = Cin;  
    assign obf_C[1] = G[0] | (P[0] & obf_C[0]);  
    assign obf_C[2] = G[1] | (P[1] & obf_C[1]);  
    assign obf_C[3] = G[2] | (P[2] & obf_C[2]);  
    assign Cout = G[3] | (P[3] & obf_C[3]);  
    assign Sum = P ^ {obf_C[3:0]};  
endmodule
